Below is a complete, runnable example of a simple production-ready REST API for a task manager app using Node.js, Express, MongoDB (via Mongoose), and JWT.  

Features:
- Users: register/login with hashed passwords, get current user
- JWT auth: protected routes
- Projects: CRUD per user
- Tasks: CRUD per project
- Basic validation & error handling
- Organized into models, controllers, routes, middleware

**Instructions:**
1. Create a new folder and `cd` into it.
2. Save each code block into the file path indicated in the comment at the top of the block.
3. Run:
   ```bash
   npm init -y
   npm install express mongoose dotenv jsonwebtoken bcryptjs cors morgan
   npm install --save-dev nodemon
   ```
4. Create `.env` file as shown.
5. Start server:
   ```bash
   npx nodemon server.js
   ```
6. Test with a tool like Postman or curl.

---

### `.env`
```env
PORT=4000
MONGO_URI=mongodb://127.0.0.1:27017/taskmanager
JWT_SECRET=super_secret_jwt_key_change_me
JWT_EXPIRES_IN=7d
NODE_ENV=development
```

---

### `server.js`
```js
// server.js - entry point

require('dotenv').config();
const app = require('./src/app');
const mongoose = require('mongoose');

const PORT = process.env.PORT || 4000;
const MONGO_URI = process.env.MONGO_URI;

// Connect to MongoDB and then start server
mongoose
  .connect(MONGO_URI)
  .then(() => {
    console.log('MongoDB connected');
    app.listen(PORT, () => {
      console.log(`Server listening on port ${PORT}`);
    });
  })
  .catch((err) => {
    console.error('MongoDB connection error:', err.message);
    process.exit(1);
  });
```

---

### `src/app.js`
```js
// src/app.js - express app setup

const express = require('express');
const morgan = require('morgan');
const cors = require('cors');

const authRoutes = require('./routes/authRoutes');
const projectRoutes = require('./routes/projectRoutes');
const taskRoutes = require('./routes/taskRoutes');
const { notFound, errorHandler } = require('./middleware/errorMiddleware');

const app = express();

// Middleware
app.use(cors());
app.use(express.json());
if (process.env.NODE_ENV !== 'production') {
  app.use(morgan('dev'));
}

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

// Routes
app.use('/api/auth', authRoutes);
app.use('/api/projects', projectRoutes);
app.use('/api/tasks', taskRoutes);

// 404 + Error handling
app.use(notFound);
app.use(errorHandler);

module.exports = app;
```

